from decimal import Decimal
import math


class Accumulator:
    def __init__(self):
        self.total = 0.0

    def add(self, x):
        self.total += x
        return self.total


def sum_values(values):
    acc = Accumulator()
    for v in values:
        acc.add(v)
    return acc.total


def test_sum():
    total = sum_values([0.1, 0.2])
    expected = 0.3
    # BUG: floating point strict equality
    assert total == expected, f'{total} != {expected}'


if __name__ == '__main__':
    test_sum()
